args.sparql:
SELECT ?state ?stateLabel WHERE {
  ?state wdt:P31 wd:Q1459 ;
         wdt:P17 wd:Q274 ;
         rdfs:label ?stateLabel.
  FILTER (LANG(?stateLabel) = 'en')
  ?state wdt:P2227 ?gdp.
} ORDER BY DESC(?gdp) LIMIT 1

