SELECT ?state ?stateLabel WHERE {
  ?state wdt:P31 wd:Q1459 ;
         wdt:P17 wd:Q274 ;
         wdt:P331 ?gdp .
  ?state rdfs:label ?stateLabel .
  FILTER (LANG(?stateLabel) = 'en')
  FILTER (isNumeric(?gdp))
} ORDER BY DESC(?gdp) LIMIT 1

SELECT ?state ?stateLabel ?gdp WHERE {
  ?state wdt:P31 wd:Q1459 ;
         wdt:P17 wd:Q274 ;
         wdt:P2227 ?gdpStatement.
  ?gdpStatement ps:P2227 ?gdpValue ;
              psv:P2227 ?gdp.
  ?state rdfs:label ?stateLabel.
  FILTER (LANG(?stateLabel) = 'en')
  FILTER (isNumeric(?gdp))
} ORDER BY DESC(?gdp) LIMIT 1

